type Widen<T> = {
  [K in keyof T]: T[K] extends string
    ? string
    : T[K] extends object
      ? Widen<T[K]>
      : T[K];
};

/** A widened version of the semantic color structure; all leaf values typed as `string`. */
export type SemanticColor = Widen<typeof semanticColorTokens.pf.light>;

/**
 * @deprecated Use `semanticColorTokens.pf.light` instead.
 * @see semanticColorTokens
 */
export const semanticLight = semanticColorTokens.pf.light;

/**
 * @deprecated Use `semanticColorTokens.pf.dark` instead.
 * @see semanticColorTokens
 */
export const semanticDark = semanticColorTokens.pf.dark;
